import React, { useState, useEffect } from 'react';
import {
  View,
  Text,
  StyleSheet,
  TouchableOpacity,
  Dimensions,
  Image,
  ScrollView,
  ActivityIndicator
, Linking, Platform } from 'react-native';
import { Ionicons, FontAwesome5, Feather, MaterialIcons } from '@expo/vector-icons';
import { StatusBar } from 'expo-status-bar';
import { SafeAreaView } from 'react-native-safe-area-context';
import { useRouter, useLocalSearchParams } from 'expo-router';
import { useDeliveryDetails, useUpdateDeliveryStatus } from '@/hooks/useDelivery';

import {  startConversation, CustomInAppToast } from '@/services/api';
import {
  startDriverLocationTracking,
  stopDriverLocationTracking,
  isTrackingLocation,
} from '@/src/background/controller';

const { width, height } = Dimensions.get('window');

const ORDER_STEPS = ['Go to Restaurant', 'Confirm Pickup', 'Go to Customer', 'Confirm Delivery'];

export default function ActiveOrderScreen() {
  const router = useRouter();
  const params = useLocalSearchParams();
  const deliveryId = params.deliveryId as string;
  const [step, setStep] = useState(0);

  // --- TanStack Query Hooks ---
  const { data, isLoading, refetch } = useDeliveryDetails(deliveryId);
  const delivery = data?.delivery;
  const updateStatusMutation = useUpdateDeliveryStatus();

  // Sync step with delivery status
  useEffect(() => {
    if (delivery) {
      const status = delivery.status;
      if (status === 'picked_up' || status === 'in_transit') {
        setStep(2);
      } else if (status === 'delivered') {
        router.replace('/driver/dashboard');
      } else {
        setStep(0);
      }
    }
  }, [delivery, delivery.status, router]);

  // Start background location tracking when this screen mounts
  useEffect(() => {
    if (!deliveryId) return;

    const startTracking = async () => {
      const alreadyTracking = await isTrackingLocation();
      if (!alreadyTracking) {
        const result = await startDriverLocationTracking(deliveryId);
        if (result.success) {
          console.log('[ActiveOrder] Background location tracking started for delivery:', deliveryId);
        } else {
          console.warn('[ActiveOrder] Could not start background tracking:', result.message);
        }
      }
    };

    startTracking();

    // Cleanup: stop tracking only if navigating away without completing
    // (completion is handled separately in handleProgress)
    return () => {
      // Don't stop here — let the dashboard or delivery completion handle it
    };
  }, [deliveryId]);

  const handleCall = (phoneNumber: string) => {
    if (!phoneNumber) {
      CustomInAppToast.show({ type: 'error', title: 'No Phone Number', message: 'Could not find a valid phone number for this contact.' });
      return;
    }
    Linking.openURL(`tel:${phoneNumber}`);
  };

  const handleChat = async (participantId: string, name: string, avatar: string) => {
    if (!participantId) return;
    try {
      const res = await startConversation(participantId);
      if (res.success && res.conversation) {
        router.push({
          pathname: '/chat/conversation',
          params: {
            conversationId: res.conversation.id,
            name: name,
            avatar: avatar,
            chatType: 'seller' // Defaulting to seller/neutral for driver chats
          }
        });
      }
    } catch (e) {
      CustomInAppToast.show({ type: 'error', title: 'Chat Error', message: 'Could not open conversation at this time.' });
    }
  };

  const handleProgress = async () => {
    try {
      if (step === 0) {
        setStep(1);
      } else if (step === 1) {
        await updateStatusMutation.mutateAsync({ deliveryId, status: 'picked_up' });
        setStep(2);
      } else if (step === 2) {
        await updateStatusMutation.mutateAsync({ deliveryId, status: 'in_transit' });
        setStep(3);
      } else if (step === 3) {
        await updateStatusMutation.mutateAsync({ deliveryId, status: 'delivered' });
        // Stop background tracking when delivery is completed
        await stopDriverLocationTracking();
        CustomInAppToast.show({ 
          type: 'success', 
          title: 'Order Completed', 
          message: 'Great job! Your earnings have been updated.' 
        });
        router.replace('/driver/dashboard');
        return;
      }
    } catch (e: any) {
      CustomInAppToast.show({ 
        type: 'error', 
        title: 'Error', 
        message: e.message || 'Failed to update status' 
      });
    }
  };

  const getButtonText = () => {
    switch (step) {
      case 0: return "Arrived at Restaurant";
      case 1: return "Confirm Pickup";
      case 2: return "Arrived at Customer";
      case 3: return "Complete Delivery";
      default: return "Complete";
    }
  };

  if (isLoading) {
    return (
      <View style={styles.centerContainer}>
        <ActivityIndicator size="large" color="#0C1559" />
      </View>
    );
  }

  if (!delivery) {
    return (
      <View style={styles.centerContainer}>
        <Text>Order not found</Text>
        <TouchableOpacity onPress={() => router.back()} style={{ marginTop: 20 }}>
          <Text style={{ color: '#0C1559', fontWeight: 'bold' }}>Go Back</Text>
        </TouchableOpacity>
      </View>
    );
  }

  const buyerProfile = delivery.order?.buyer?.user_profiles;
  const storeDetails = delivery.order?.store;

  return (
    <View style={styles.container}>
      <StatusBar style="dark" />

      {/* --- MAP PLACEHOLDER --- */}
      <View style={styles.mapContainer}>
        <Image
          source={{ uri: 'https://i.imgur.com/83g2v6z.png' }}
          style={styles.mapImage}
        />
        <SafeAreaView style={styles.safeMapOverlay}>
          <TouchableOpacity onPress={() => router.back()} style={styles.backBtn}>
            <Ionicons name="arrow-back" size={24} color="#0F172A" />
          </TouchableOpacity>
        </SafeAreaView>
      </View>

      {/* --- BOTTOM SHEET --- */}
      <View style={styles.bottomSheet}>
        <View style={styles.handleBar} />

        <ScrollView showsVerticalScrollIndicator={false} contentContainerStyle={{ paddingBottom: 100 }}>

          <View style={styles.statusRow}>
            <Text style={styles.statusTitle}>{ORDER_STEPS[step]}</Text>
            <Text style={styles.timeRemaining}>~ {delivery?.estimated_time || (step === 0 ? '5' : '15')} mins</Text>
          </View>

          {/* Address Info */}
          <View style={styles.locationCard}>
            <View style={styles.iconCircle}>
              <MaterialIcons name={step <= 1 ? "storefront" : "location-pin"} size={24} color="#0C1559" />
            </View>
            <View style={{ flex: 1, marginLeft: 15 }}>
              <Text style={styles.locationLabel}>{step <= 1 ? "Pick Up At" : "Deliver To"}</Text>
              <Text style={styles.locationName}>
                {step <= 1 ? (storeDetails?.store_name || "Store") : (buyerProfile?.full_name || "Customer")}
              </Text>
              <Text style={styles.locationAddress} numberOfLines={2}>
                {step <= 1 ? (delivery.pickup_address) : (delivery.delivery_address)}
              </Text>
            </View>
            <TouchableOpacity 
              style={styles.navBtn} 
              onPress={() => {
                const addr = step <= 1 ? delivery.pickup_address : delivery.delivery_address;
                const url = Platform.select({
                  ios: `maps:0,0?q=${addr}`,
                  android: `geo:0,0?q=${addr}`
                });
                if (url) Linking.openURL(url);
              }}
            >
              <FontAwesome5 name="location-arrow" size={18} color="#FFF" />
            </TouchableOpacity>
          </View>

          {/* Contact Section - Showing both for convenience */}
          <Text style={styles.summaryTitle}>Contacts</Text>
          
          {/* Store Contact */}
          <View style={styles.contactRow}>
            <View style={styles.customerInfo}>
              <Image
                source={{ uri: storeDetails?.logo_url || 'https://api.dicebear.com/9.x/avataaars/png?seed=Store' }}
                style={styles.customerImg}
              />
              <View>
                <Text style={styles.customerName}>{storeDetails?.store_name || "Store"}</Text>
                <Text style={styles.customerRole}>Seller</Text>
              </View>
            </View>
            <View style={styles.actionButtons}>
              <TouchableOpacity
                style={styles.circleBtn}
                onPress={() => handleChat(storeDetails?.owner_id, storeDetails?.store_name, storeDetails?.logo_url)}
              >
                <Ionicons name="chatbubble-ellipses-outline" size={22} color="#0C1559" />
              </TouchableOpacity>
              <TouchableOpacity 
                style={[styles.circleBtn, { backgroundColor: '#E0E7FF' }]}
                onPress={() => handleCall(storeDetails?.phone)}
              >
                <Ionicons name="call-outline" size={22} color="#0C1559" />
              </TouchableOpacity>
            </View>
          </View>

          {/* Customer Contact */}
          <View style={styles.contactRow}>
            <View style={styles.customerInfo}>
              <Image
                source={{ uri: buyerProfile?.avatar_url || 'https://api.dicebear.com/9.x/avataaars/png?seed=Sarah' }}
                style={styles.customerImg}
              />
              <View>
                <Text style={styles.customerName}>{buyerProfile?.full_name || "Customer"}</Text>
                <Text style={styles.customerRole}>Recipient</Text>
              </View>
            </View>
            <View style={styles.actionButtons}>
              <TouchableOpacity
                style={styles.circleBtn}
                onPress={() => handleChat(delivery.order?.buyer_id, buyerProfile?.full_name, buyerProfile?.avatar_url)}
              >
                <Ionicons name="chatbubble-ellipses-outline" size={22} color="#0C1559" />
              </TouchableOpacity>
              <TouchableOpacity 
                style={[styles.circleBtn, { backgroundColor: '#E0E7FF' }]}
                onPress={() => handleCall(buyerProfile?.phone)}
              >
                <Ionicons name="call-outline" size={22} color="#0C1559" />
              </TouchableOpacity>
            </View>
          </View>

          <View style={styles.divider} />

          {/* Order Items Summary */}
          <View style={styles.orderSummary}>
            <Text style={styles.summaryTitle}>Order Details #{delivery.order?.order_number}</Text>
            {delivery.order?.order_items?.map((item: any, index: number) => (
              <View key={index} style={styles.orderItem}>
                <Text style={styles.qty}>{item.quantity}x</Text>
                <Text style={styles.itemName}>{item.product_title}</Text>
                <Text style={styles.itemPrice}>₵{(item.unit_price * item.quantity).toFixed(2)}</Text>
              </View>
            ))}
            {(!delivery.order?.order_items || delivery.order.order_items.length === 0) && (
              <Text style={styles.noItems}>No item details available</Text>
            )}
            <View style={styles.totalRow}>
                <Text style={styles.totalLabel}>Total Price</Text>
                <Text style={styles.totalValue}>₵{delivery.order?.total_amount?.toFixed(2) || '0.00'}</Text>
            </View>
          </View>

        </ScrollView>

        {/* --- MAIN ACTION BUTTON --- */}
        <View style={styles.footer}>
          <TouchableOpacity
            style={[styles.mainBtn, step === 3 && styles.completeBtn, updateStatusMutation.isPending && { opacity: 0.8 }]}
            onPress={handleProgress}
            activeOpacity={0.8}
            disabled={updateStatusMutation.isPending}
          >
            {updateStatusMutation.isPending ? (
              <ActivityIndicator color={step === 3 ? "#FFF" : "#0C1559"} />
            ) : (
              <>
                <Text style={[styles.mainBtnText, step === 3 && { color: '#FFF' }]}>
                  {getButtonText()}
                </Text>
                <Feather name="arrow-right" size={20} color={step === 3 ? "#FFF" : "#0C1559"} />
              </>
            )}
          </TouchableOpacity>
        </View>
      </View>
    </View>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1, backgroundColor: '#F8FAFC' },
  centerContainer: { flex: 1, justifyContent: 'center', alignItems: 'center' },

  // Map Section
  mapContainer: { height: height * 0.45, width: '100%', backgroundColor: '#E2E8F0' },
  mapImage: { width: '100%', height: '100%', resizeMode: 'cover', opacity: 0.8 },
  safeMapOverlay: { position: 'absolute', top: 0, left: 20 },
  backBtn: { backgroundColor: '#FFF', padding: 10, borderRadius: 12, shadowColor: '#000', shadowOpacity: 0.1, shadowRadius: 5, elevation: 3 },

  // Bottom Sheet
  bottomSheet: {
    flex: 1, backgroundColor: '#FFF', borderTopLeftRadius: 30, borderTopRightRadius: 30,
    marginTop: -30, paddingHorizontal: 24, paddingTop: 10
  },
