import  { useEffect, useRef} from 'react';
import { View, Text, StyleSheet, TouchableOpacity, Dimensions, ImageBackground, Animated , Appearance } from 'react-native';
import { router } from 'expo-router';
import { LinearGradient } from 'expo-linear-gradient';
import { StatusBar } from 'expo-status-bar';

import { SafeAreaView } from 'react-native-safe-area-context';
// import * as SecureStore from 'expo-secure-store'; // ⛔ temporarily disabled

import {  getUserData, secureStorage } from '@/services/api';

const { width, height } = Dimensions.get('window');

const IndexScreen = () => {
  const colorScheme = Appearance.getColorScheme();
  const isDarkMode = colorScheme === 'dark';
  const fadeAnim = useRef(new Animated.Value(0)).current; // animation value for logo opacity
  const fadeOutAnim = useRef(new Animated.Value(1)).current; // Screen fade-out overlay
  const bgScale = useRef(new Animated.Value(1)).current; // background zoom
  const bgTranslateY = useRef(new Animated.Value(0)).current; // background drift

  useEffect(() => {
    // Parallel fade + background zoom animations
    Animated.parallel([
      Animated.timing(fadeAnim, {
        toValue: 1,
        duration: 2200,
        useNativeDriver: true,
      }),
      Animated.timing(bgScale, {
        toValue: 1.08,
        duration: 2800,
        useNativeDriver: true,
      }),
      Animated.timing(bgTranslateY, {
        toValue: -12,
        duration: 3000,
        useNativeDriver: true,
      }),
    ]).start();

    // Perform auth check concurrently with animation wait
    const authCheckPromise = async () => {
      try {
        const token = await secureStorage.getItem('userToken');
        if (!token) return '/getstarted';

        const user = await getUserData();
        const role = user.role?.toLowerCase();

        if (user.requiresRoleSelection || !role || role === 'none') return '/role';
        if (role === 'customer' || role === 'buyer') return '/home';
        if (role === 'seller') return '/business/dashboard';
        if (role === 'driver') return '/driver';
        if (role === 'admin') return '/admin/dashboard';

        return '/home';
      } catch (error) {
        console.warn('Startup Auth Check Failed:', error);
        return '/getstarted'; // Session invalid or network issue
      }
    };

    const runStartup = async () => {
      const minWaitPromise = new Promise((resolve) => setTimeout(resolve, 2000));
      const [nextRoute] = await Promise.all([authCheckPromise(), minWaitPromise]);

      Animated.timing(fadeOutAnim, {
        toValue: 0,
        duration: 1000, // smooth fade out
        useNativeDriver: true,
      }).start(() => {
        router.replace(nextRoute as any);
      });
    };

    runStartup();
  }, [bgScale, bgTranslateY, fadeAnim, fadeOutAnim]);

  return (
    <View style={styles.container}>
      <Animated.View
        style={{
          flex: 1,
          transform: [{ scale: bgScale }, { translateY: bgTranslateY }],
        }}
      >
      <ImageBackground
        source={require('../assets/images/shopbackground.png')}
        style={styles.backgroundImage}
        imageStyle={styles.backgroundImageStyle}
      >
        <View style={styles.overlay} />
        <StatusBar style="light" translucent backgroundColor="transparent" />

        <SafeAreaView style={styles.safeArea} edges={['right', 'bottom', 'left']}>

          {/* Centered logo (responsive true center) */}
          <View style={styles.logoAbsoluteContainer}>
            <Animated.Image
              source={require('../assets/images/iconwhite.png')}
              style={[styles.logo, { opacity: fadeAnim }]}
              resizeMode="contain"
            />
          </View>

          {/* Hidden buttons (keep functionality for later) */}
          <View style={styles.footer}>
            <TouchableOpacity
              style={[styles.createAccountButton, { opacity: 0 }]}
              onPress={() => router.push('/register')}
              activeOpacity={0.8}
            >
              <LinearGradient
                colors={['#1b7c22', '#34a853']}
                style={styles.gradientButton}
                start={{ x: 0, y: 0 }}
                end={{ x: 1, y: 0 }}
              >
                <Text style={styles.createAccountText}>Create Account</Text>
              </LinearGradient>
            </TouchableOpacity>

            <TouchableOpacity
              style={[styles.loginButton, { opacity: 0 }]}
              onPress={() => router.push('/login')}
              activeOpacity={0.7}
            >
              <Text style={styles.loginText}>Already have an account? Login</Text>
            </TouchableOpacity>
          </View>
        </SafeAreaView>
      </ImageBackground>
      </Animated.View>

      {/* Screen fade-out overlay */}
      <Animated.View
        style={[
          StyleSheet.absoluteFill,
          {
            backgroundColor: '#061f65',
            opacity: fadeOutAnim.interpolate({
              inputRange: [0, 1],
              outputRange: [0, 0.9],
            }),
          },
        ]}
      />
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#061f65ff',
  },
  backgroundImage: {
    flex: 1,
    width: '100%',
    height: '100%',
  },
  backgroundImageStyle: {
    opacity: 0.5,
    transform: [
      { rotate: '-20deg' },
      { translateX: 30 },
      { translateY: 20 },
    ],
    resizeMode: 'contain',
  },
  overlay: {
    ...StyleSheet.absoluteFillObject,
    backgroundColor: '#061f65ff',
    opacity: 0.93,
  },
  safeArea: {
    flex: 1,
  },
    logoAbsoluteContainer: {
      position: 'absolute',
      top: 0,
      left: 0,
      right: 0,
      bottom: 0,
      justifyContent: 'center',
      alignItems: 'center',
      zIndex: 2,
    },
    logo: {
      width: width * 0.55,
      height: height * 0.12,
    },

  footer: {
    paddingHorizontal: 30,
    paddingBottom: 40,
  },
  createAccountButton: {
    width: '100%',
    borderRadius: 25,
    marginBottom: 16,
  },
  gradientButton: {
    paddingVertical: 16,
    borderRadius: 25,
    alignItems: 'center',
  },
  createAccountText: {
    color: '#ffffff',
    fontSize: 18,
    fontWeight: '600',
  },
  loginButton: {
    width: '100%',
    paddingVertical: 16,
    borderRadius: 25,
    alignItems: 'center',
  },
  loginText: {
    color: '#ffffff',
    fontSize: 16,
    fontWeight: '500',
  },
});

export default IndexScreen;

import { router } from 'expo-router';
import React, {  useState } from 'react';
import { View, Text, TextInput, TouchableOpacity, ActivityIndicator, StyleSheet, Image, KeyboardAvoidingView, Platform, Pressable, Keyboard, Dimensions , Appearance } from 'react-native';
import { Ionicons } from '@expo/vector-icons';
import { CustomInAppToast } from "@/components/InAppToastHost";
import { StatusBar } from 'expo-status-bar';
import { loginUser } from '@/services/api';

import * as Location from 'expo-location';

const { width } = Dimensions.get('window');



const LoginScreen = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const isDarkMode = Appearance.getColorScheme() === 'dark';

  // Handle Sign In
  const handleLogin = async () => {
    try {
      setLoading(true);

      // Get device location
      let latitude = 0;
      let longitude = 0;
      try {
        const { status } = await Location.requestForegroundPermissionsAsync();
        if (status === 'granted') {
          const location = await Location.getCurrentPositionAsync({});
          latitude = location.coords.latitude;
          longitude = location.coords.longitude;
        }
      } catch (locationError) {
        console.log('Location access denied or unavailable');
      }

      const response = await loginUser(email, password, latitude, longitude);



      if (response.message === "Login successful") {

        CustomInAppToast.show({
          type: 'success',
          title: 'Login Successful 😊',
          message: 'Welcome back! 🎉',
        });

        // Check if user needs to select a role (using the needsRole flag from API)
        if (response.needsRole) {
          // User has no role assigned, redirect to role selection
          router.push('/role');
        } else {
          // User has a role, proceed with normal navigation
          const userRole = response.role?.toLowerCase();

          if (userRole === 'customer' || userRole === 'buyer') {
            router.push("/home");
          } else if (userRole === 'seller') {
            router.push("/business/dashboard");
          } else if (userRole === 'driver') {
            router.push("/driver");
          } else if (userRole === 'admin') {
            router.push("/admin/dashboard");
          }
        }
      } else {
        CustomInAppToast.show({
          type: 'error',
          title: 'Login Failed ❌',
          message: response.message || 'Please try again.',
        });
      }
    } catch (error: any) {
      CustomInAppToast.show({
        type: 'error',
        title: 'Sign In Failed ⚠️',
        message: error.message || 'Something went wrong.',
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <View style={styles.container}>
      <StatusBar style="dark" translucent backgroundColor="transparent" />

      <KeyboardAvoidingView
        behavior={Platform.OS === 'ios' ? 'padding' : 'height'}
        style={{ flex: 1 }}
      >
        <Pressable onPress={Keyboard.dismiss} style={{ flex: 1 }}>
          <View style={styles.innerContainer}>
            {/* Logo */}
            <Image
              source={require('../assets/images/icondark.png')}
              style={styles.logo}
            />

            {/* Title */}
            <Text style={styles.title}>Sign into your account</Text>
            <Text style={styles.subtitle}>
              Welcome back, you’ve been missed!
            </Text>

            {/* Email Input */}
            <View style={styles.inputContainer}>
              <Ionicons name="mail" size={20} color="#333" />
              <TextInput
                style={styles.input}
                placeholder="Enter your email"
                placeholderTextColor="#888"
                keyboardType="email-address"
                autoCapitalize="none"
                value={email}
                onChangeText={setEmail}
              />
            </View>

            {/* Password Input */}
            <View style={styles.inputContainer}>
              <Ionicons name="lock-closed" size={20} color="#333" />
              <TextInput
                style={styles.input}
                placeholder="Password"
                placeholderTextColor="#888"
                secureTextEntry={!showPassword}
                autoCapitalize="none"
                value={password}
                onChangeText={setPassword}
              />
              <TouchableOpacity
                onPress={() => setShowPassword(!showPassword)}
                style={styles.eyeIcon}
              >
                <Ionicons
                  name={showPassword ? 'eye' : 'eye-off'}
                  size={20}
                  color="#111827"
                />
              </TouchableOpacity>
            </View>

            {/* Forgot Password */}
            <TouchableOpacity onPress={() => router.push('/forgotPassword')}>
              <Text style={styles.forgotPassword}>Forgot password?</Text>
            </TouchableOpacity>


            {/* Sign in (solid pill) */}
            <TouchableOpacity
              style={[styles.signInButton, loading && styles.disabledButton]}
              onPress={handleLogin}
              disabled={loading}
            >
              {loading ? (
                <ActivityIndicator color="#fff" />
              ) : (
                <Text style={styles.signInText}>Sign in</Text>
              )}
            </TouchableOpacity>

            {/* Register (outlined pill) */}
            <TouchableOpacity
              style={styles.registerButton}
              onPress={() => router.push('/register')}
            >
              <Text style={styles.registerText}>
                Not registered? <Text style={styles.registerBold}>Sign up now!</Text>
              </Text>
            </TouchableOpacity>

            {/* Bottom Logos */}
            <View style={styles.bottomLogos}>
              <Image
                source={require('../assets/images/icon.png')}
                style={styles.circleLogo}
              />
              <Image
                source={require('../assets/images/icondark.png')}
                style={styles.brandLogo}
              />
            </View>
          </View>
        </Pressable>
      </KeyboardAvoidingView>
    </View>
  );
};


