import { router } from 'expo-router';
import React, {  useState } from 'react';
import { View, Text, ScrollView, TextInput, TouchableOpacity, ActivityIndicator, StyleSheet, Image, KeyboardAvoidingView, Platform, Pressable, Keyboard, Dimensions , Appearance } from 'react-native';
import { registerUser } from '@/services/api';
import { Ionicons } from '@expo/vector-icons';
import CountryPicker from '@/components/CountryPicker';
import { CustomInAppToast } from "@/components/InAppToastHost";
import { LinearGradient } from 'expo-linear-gradient';
import { StatusBar } from 'expo-status-bar';

import Swiper from 'react-native-swiper';


const { width } = Dimensions.get('window');

const RegisterScreen = () => {
  const [name, setName] = useState('');
  const [phoneNumber, setPhoneNumber] = useState('');
  const [countryCode, setCountryCode] = useState('GH');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [callingCode, setCallingCode] = useState('233');
  const [showCountryPicker, setShowCountryPicker] = useState(false);
  const [loading, setLoading] = useState(false);
  const isDarkMode = Appearance.getColorScheme() === 'dark';

  const formatPhoneNumber = (callingCode: string, phoneNumber: string) => {
    // Remove leading plus from code if present to prevent ++
    const cleanCode = callingCode.replace('+', '');
    // Remove leading zero from number if present
    const formattedNumber = phoneNumber.replace(/^0/, '');
    return `+${cleanCode}${formattedNumber}`;
  };


  const handleRegister = async () => {
    try {
      const fullPhoneNumber = formatPhoneNumber(callingCode, phoneNumber);
      setLoading(true);
      const data = await registerUser(name, email, password, fullPhoneNumber);
      if (data.message === "User created successfully") {
        CustomInAppToast.show({
          type: 'success',
          title: 'Sign up Successful',
          message: 'Welcome! 🎉',
        });
        router.push('/login');
      } else {
        CustomInAppToast.show({
          type: 'error',
          title: 'Sign up Failed',
          message: data.message || 'Please try again.',
        });
      }
    } catch (error: any) {
      CustomInAppToast.show({
        type: 'error',
        title: 'Sign Up Failed',
        message: error.message || 'Something went wrong.',
      });
    } finally {
      setLoading(false);
    }
  };


  return (
    <LinearGradient
      colors={['#EAF0FF', '#F4F6FF']}
      style={{ flex: 1 }}
    >
      <StatusBar style="dark" translucent backgroundColor="transparent" />
      <KeyboardAvoidingView
        behavior={Platform.OS === 'ios' ? 'padding' : 'height'}
        style={styles.container}
      >
        <Pressable onPress={Keyboard.dismiss} style={{ flex: 1 }}>
          <ScrollView contentContainerStyle={styles.scrollContent}>

            {/* 🖼️ Top Banner Carousel */}
            <View style={styles.bannerContainer}>
              <Swiper
                autoplay
                autoplayTimeout={3}
                loop
                showsPagination
                dotStyle={styles.dot}
                activeDotStyle={styles.activeDot}
              >
                <View style={styles.slide}>
                  <Image
                    source={require('../assets/images/customer.jpg')}
                    style={styles.bannerImage}
                    resizeMode="cover"
                  />
                </View>
                <View style={styles.slide}>
                  <Image
                    source={require('../assets/images/seller.jpg')}
                    style={styles.bannerImage}
                    resizeMode="cover"
                  />
                </View>
                <View style={styles.slide}>
                  <Image
                    source={require('../assets/images/driver.jpg')}
                    style={styles.bannerImage}
                    resizeMode="cover"
                  />
                </View>
              </Swiper>
            </View>

            {/* 🧾 Input fields */}
            <View style={styles.formContainer}>
              <View style={styles.inputContainer}>
                <Ionicons name="person" size={20} color="#1b1b1b" style={styles.inputIcon} />
                <TextInput
                  style={styles.input}
                  placeholder="Enter your name"
                  placeholderTextColor="#666"
                  autoCorrect={false}
                  value={name}
                  onChangeText={setName}
                />
              </View>

              <View style={styles.inputContainer}>
                <Ionicons name="mail" size={20} color="#1b1b1b" style={styles.inputIcon} />
                <TextInput
                  style={styles.input}
                  placeholder="Enter your email"
                  placeholderTextColor="#666"
                  keyboardType="email-address"
                  autoCapitalize="none"
                  autoCorrect={false}
                  value={email}
                  onChangeText={setEmail}
                />
              </View>

              <View style={styles.inputContainer}>
                <TouchableOpacity
                  style={styles.countryCodeButton}
                  onPress={() => setShowCountryPicker(true)}
                >
                  <Text style={styles.callingCode}>{callingCode}</Text>
                  <Ionicons name="chevron-down-sharp" size={16} color="#444" />
                </TouchableOpacity>
                <TextInput
                  style={[styles.input, styles.phoneInput]}
                  placeholder="Phone number"
                  placeholderTextColor="#666"
                  keyboardType="phone-pad"
                  value={phoneNumber}
                  onChangeText={setPhoneNumber}
                />
                <CountryPicker
                  visible={showCountryPicker}
                  onClose={() => setShowCountryPicker(false)}
                  onSelect={(country) => {
                    // 1. Use 'code' instead of 'cca2'
                    setCountryCode(country.code);

                    // 2. Use 'dial_code' instead of 'callingCode[0]'
                    setCallingCode(country.dial_code);
                  }}
                />
              </View>

              <View style={styles.inputContainer}>
                <Ionicons name="lock-closed" size={20} color="#1b1b1b" style={styles.inputIcon} />
                <TextInput
                  style={[styles.input, styles.passwordInput]}
                  placeholder="Password"
                  placeholderTextColor="#666"
                  secureTextEntry={!showPassword}
                  autoCapitalize="none"
                  autoCorrect={false}
                  value={password}
                  onChangeText={setPassword}
                />
                <TouchableOpacity style={styles.eyeIcon} onPress={() => setShowPassword(!showPassword)}>
                  <Ionicons
                    name={showPassword ? 'eye' : 'eye-off'}
                    size={20}
                    color="#666"
                  />
                </TouchableOpacity>
              </View>

              {/* Sign Up Button */}
              <TouchableOpacity style={styles.button} onPress={handleRegister}>
                {loading ? (
                  <ActivityIndicator size="small" color="#FFF" />
                ) : (
                  <Text style={styles.buttonText}>Sign Up</Text>
                )}
              </TouchableOpacity>

              <Text style={styles.roleText}>Select your role to continue registration.</Text>

              {/* Register (outlined pill) */}
              <TouchableOpacity
                style={styles.loginButton}
                onPress={() => router.push('/login')}
              >
                <Text style={styles.loginText}>
                  Already registered? <Text style={styles.loginBold}>Sign in now!</Text>
                </Text>
              </TouchableOpacity>
              <View style={styles.bottomLogos}>
                <Image source={require('../assets/images/icon.png')} style={styles.circleLogo} />
                <Image source={require('../assets/images/icondark.png')} style={styles.brandLogo} />
              </View>
            </View>
          </ScrollView>
        </Pressable>
      </KeyboardAvoidingView>
    </LinearGradient>
  );
};

