import React, { useState, useEffect, useCallback } from 'react';
import {
    View,
    Text,
    StyleSheet,
    TouchableOpacity,
    ScrollView,
    TextInput,
    ActivityIndicator,
    Alert,
    Image,
    Dimensions,
} from 'react-native';
import { SafeAreaView } from 'react-native-safe-area-context';
import { Ionicons } from '@expo/vector-icons';
import { useLocalSearchParams, useRouter } from 'expo-router';
import { LinearGradient } from 'expo-linear-gradient';
import { StatusBar } from 'expo-status-bar';
import { getProductById, createProductReview, getReviewableProducts } from '@/services/api';
import { ReviewSkeleton } from '@/components/skeletons/ReviewSkeleton';

const { width } = Dimensions.get('window');

const ProductReviewScreen = () => {
    const { id } = useLocalSearchParams();
    const router = useRouter();
    const [product, setProduct] = useState<any>(null);
    const [matchingOrderId, setMatchingOrderId] = useState<string | null>(null);
    const [loading, setLoading] = useState(true);
    const [submitting, setSubmitting] = useState(false);

    const [rating, setRating] = useState(5);
    const [comment, setComment] = useState('');

    const fetchData = useCallback(async () => {
        try {
            // 1. Fetch product details
            const res = await getProductById(id as string);
            if (res && res.success) {
                setProduct(res.product);

                // 2. Try to find a matching order for this product (to satisfy DB constraints)
                try {
                    const reviewable = await getReviewableProducts();
                    const match = reviewable.data?.find((item: any) => item.productId === res.product.id || item.productId === res.product._id);
                    if (match) setMatchingOrderId(match.orderId);
                } catch (err) {
                    console.log("Could not find matching order, submission might fail if DB requires it", err);
                }
            } else {
                Alert.alert('Error', 'Could not find product to review');
                router.back();
            }
        } catch (e) {
            console.error(e);
            Alert.alert('Error', 'Failed to load product details');
            router.back();
        } finally {
            setLoading(false);
        }
    }, [id, router]);

    useEffect(() => {
        if (id) fetchData();
    }, [fetchData, id]);

    const handleSubmit = async () => {
        if (rating === 0) {
            Alert.alert('Required', 'Please give a star rating');
            return;
        }

        try {
            if (!matchingOrderId) {
                Alert.alert(
                    "Verified Purchase Required", 
                    "To ensure authentic feedback, Shopyos only allows reviews for products you have successfully purchased and received. Please check your order history."
                );
                return;
            }

            setSubmitting(true);
            await createProductReview({
                productId: product.id || product._id,
                orderId: matchingOrderId,
                rating: rating,
                reviewText: comment
            });

            Alert.alert('Thank You!', 'Your review has been shared with the community.', [
                { text: 'OK', onPress: () => router.back() }
            ]);
        } catch (e: any) {
            console.error(e);
            Alert.alert('Error', e.message || 'Failed to submit review');
        } finally {
            setSubmitting(false);
        }
    };

    const StarRating = ({ currentRating, onRate }: { currentRating: number, onRate: (r: number) => void }) => (
        <View style={styles.starRow}>
            {[1, 2, 3, 4, 5].map((s) => (
                <TouchableOpacity key={s} onPress={() => onRate(s)} style={{ paddingHorizontal: 6 }}>
                    <Ionicons
                        name={s <= currentRating ? "star" : "star-outline"}
                        size={36}
                        color={s <= currentRating ? "#F59E0B" : "#CBD5E1"}
                    />
                </TouchableOpacity>
            ))}
        </View>
    );

    if (loading) return <ReviewSkeleton />;

    return (
        <View style={styles.mainContainer}>
            <StatusBar style="light" backgroundColor="#0C1559" />

            <LinearGradient colors={['#0C1559', '#1e3a8a']} style={styles.header}>
                <SafeAreaView edges={['top', 'left', 'right']}>
                    <View style={styles.headerRow}>
                        <TouchableOpacity onPress={() => router.back()} style={styles.backBtn}>
                            <Ionicons name="close" size={24} color="#FFF" />
                        </TouchableOpacity>
                        <Text style={styles.headerTitle}>Review Product</Text>
                        <View style={{ width: 40 }} />
                    </View>
                </SafeAreaView>
            </LinearGradient>

            <ScrollView showsVerticalScrollIndicator={false} contentContainerStyle={styles.scrollContent}>

                {/* Product Detail Card */}
                <View style={styles.section}>
                    <View style={styles.card}>
                        <View style={styles.productInfo}>
                            <View style={styles.productImageContainer}>
                                <Image
                                    source={product?.images?.[0] ? { uri: product.images[0] } : require('../../../assets/images/icon.png')}
                                    style={styles.productImage}
                                />
                            </View>
                            <View style={{ flex: 1 }}>
                                <Text style={styles.productName} numberOfLines={2}>{product?.name}</Text>
                                <Text style={styles.categoryName}>{product?.category}</Text>
                            </View>
                        </View>

                        <View style={styles.divider} />

                        <Text style={styles.ratingTitle}>How would you rate this item?</Text>
                        <StarRating currentRating={rating} onRate={setRating} />

                        <TextInput
                            style={styles.commentInput}
                            placeholder="Share your experience with this product... (e.g., quality, durability, fit)"
                            multiline
                            numberOfLines={5}
                            value={comment}
                            onChangeText={setComment}
                        />
                    </View>
                </View>

                <TouchableOpacity
                    style={[styles.submitBtnContainer, submitting && { opacity: 0.7 }]}
                    onPress={handleSubmit}
                    disabled={submitting}
                >
                    <LinearGradient colors={['#A3E635', '#65a30d']} style={styles.submitBtn}>
                        {submitting ? (
                            <ActivityIndicator color="#0C1559" />
                        ) : (
                            <Text style={styles.submitBtnText}>Post Review</Text>
                        )}
                    </LinearGradient>
                </TouchableOpacity>

            </ScrollView>
        </View>
    );
};

