import React, { useEffect, useState } from 'react';
import {
  View,
  Text,
  StyleSheet,
  TouchableOpacity,
  Modal,
  Image,
  Dimensions,
  SafeAreaView,
} from 'react-native';
import { Ionicons, MaterialCommunityIcons } from '@expo/vector-icons';
import { BlurView } from 'expo-blur';

const { width, height } = Dimensions.get('window');

interface CallOverlayProps {
  isVisible: boolean;
  status: 'incoming' | 'outgoing' | 'connected' | 'ended';
  name: string;
  avatar: string;
  isMuted: boolean;
  isSpeakerOn: boolean;
  onAccept: () => void;
  onReject: () => void;
  onEnd: () => void;
  onToggleMute: () => void;
  onToggleSpeaker: () => void;
}

export const CallOverlay: React.FC<CallOverlayProps> = ({
  isVisible,
  status,
  name,
  avatar,
  isMuted,
  isSpeakerOn,
  onAccept,
  onReject,
  onEnd,
  onToggleMute,
  onToggleSpeaker,
}) => {
  const [timer, setTimer] = useState(0);

  useEffect(() => {
    let interval: any;
    if (status === 'connected') {
      interval = setInterval(() => {
        setTimer((prev) => prev + 1);
      }, 1000);
    } else {
      setTimer(0);
    }
    return () => clearInterval(interval);
  }, [status]);

  const formatTimer = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  if (!isVisible) return null;

  return (
    <Modal visible={isVisible} animationType="slide" transparent>
      <View style={styles.container}>
        <Image
          source={{ uri: avatar || 'https://via.placeholder.com/150' }}
          style={StyleSheet.absoluteFill}
          blurRadius={50}
        />
        <BlurView intensity={80} style={StyleSheet.absoluteFill} tint="dark" />

        <SafeAreaView style={styles.safeArea}>
          <View style={styles.content}>
            <View style={styles.header}>
              <View style={styles.avatarContainer}>
                <Image
                  source={{ uri: avatar || 'https://via.placeholder.com/150' }}
                  style={styles.avatar}
                />
                {status === 'connected' && (
                  <View style={styles.pulseContainer}>
                    <View style={styles.pulse} />
                  </View>
                )}
              </View>
              <Text style={styles.name}>{name}</Text>
              <Text style={styles.statusText}>
                {status === 'incoming'
                  ? 'Incoming Voice Call'
                  : status === 'outgoing'
                  ? 'Ringing...'
                  : status === 'connected'
                  ? formatTimer(timer)
                  : 'Call Ended'}
              </Text>
            </View>

            <View style={styles.footer}>
              {status === 'incoming' ? (
                <View style={styles.actionButtons}>
                  <TouchableOpacity
                    style={[styles.circleButton, styles.rejectButton]}
                    onPress={onReject}
                  >
                    <Ionicons name="close" size={32} color="white" />
                  </TouchableOpacity>
                  <TouchableOpacity
                    style={[styles.circleButton, styles.acceptButton]}
                    onPress={onAccept}
                  >
                    <Ionicons name="call" size={32} color="white" />
                  </TouchableOpacity>
                </View>
              ) : (
                <View style={styles.actionButtons}>
                  {status === 'connected' && (
                    <TouchableOpacity style={styles.squareButton} onPress={onToggleMute}>
                      <Ionicons 
                        name={isMuted ? "mic-off" : "mic"} 
                        size={24} 
                        color={isMuted ? "#ef4444" : "white"} 
                      />
                      <Text style={[styles.buttonLabel, isMuted && { color: '#ef4444' }]}>
                        {isMuted ? "Unmute" : "Mute"}
                      </Text>
                    </TouchableOpacity>
                  )}
                  <TouchableOpacity
                    style={[styles.circleButton, styles.endButton]}
                    onPress={onEnd}
                  >
                    <MaterialCommunityIcons name="phone-hangup" size={32} color="white" />
                  </TouchableOpacity>
                  {status === 'connected' && (
                    <TouchableOpacity style={styles.squareButton} onPress={onToggleSpeaker}>
                      <Ionicons 
                        name={isSpeakerOn ? "volume-high" : "volume-medium"} 
                        size={24} 
                        color={isSpeakerOn ? "#22c55e" : "white"} 
                      />
                      <Text style={[styles.buttonLabel, isSpeakerOn && { color: '#22c55e' }]}>
                        Speaker
                      </Text>
                    </TouchableOpacity>
                  )}
                </View>
              )}
            </View>
          </View>
        </SafeAreaView>
      </View>
    </Modal>
  );
};

