  }, []);

  const playNotificationChime = async () => {
    try {
      const { sound } = await Audio.Sound.createAsync(
        notificationWav,
        { isLooping: false, volume: 0.25, shouldPlay: true }
      );
      sound.setOnPlaybackStatusUpdate((status) => {
        if (status.isLoaded && status.didJustFinish) {
          sound.unloadAsync().catch(() => null);
        }
      });
    } catch (e) {
      console.warn('Could not play notification chime:', e);
    }
  };

  const stopRingtone = async () => {
    try {
      if (soundRef.current) {
        const status = await soundRef.current.getStatusAsync();
        if (status.isLoaded) {
          await soundRef.current.stopAsync();
          await soundRef.current.unloadAsync();
        }
        soundRef.current = null;
      }
    } catch (e) {
      console.warn('Could not stop ringtone:', e);
    }
  };

  const fetchChats = async () => {
    try {
      const token = await secureStorage.getItem('userToken') || await secureStorage.getItem('businessToken');
      if (!token) return;

      let activeUserId = await storage.getItem('userId');
      if (!activeUserId) {
        try {
          const me = await getUserData();
          if (me?.id) {
            activeUserId = me.id;
            await storage.setItem('userId', activeUserId!);
          }
        } catch (e) {}
      }
      if (activeUserId) setCurrentUserId(activeUserId);

      const response = await getConversations();
      if (response?.conversations) {
        const formatted: Conversation[] = response.conversations.map((c: any) => {
          const p = c.otherParticipant;
          let name = 'Unknown User';
          let avatar = 'https://via.placeholder.com/150';
          if (p) {
            if (p.store) {
              name = p.store.store_name || name;
              avatar = p.store.logo_url || avatar;
            } else {
              const profile = Array.isArray(p.user_profiles) ? p.user_profiles[0] : p.user_profiles;
              if (profile) {
                name = profile.full_name || name;
                avatar = profile.avatar_url || avatar;
              }
            }
          }
          const lastMsgSenderId = c.lastMessage?.sender_id;
          const isMe = activeUserId && lastMsgSenderId === activeUserId;
          const time = c.updatedAt ? new Date(c.updatedAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : '';
          return {
            id: c.id,
            name,
            avatar,
            lastMessage: c.lastMessage?.content || 'No messages yet',
            time,
            unread: c.unreadCount || 0,
            online: false,
            messages: c.lastMessage ? [{ id: c.lastMessage.id, text: c.lastMessage.content, sender: isMe ? 'me' : 'them', time }] : [],
            otherParticipant: p,
          };
        });

        setBuyerChats(formatted.filter(c => c.otherParticipant?.store?.id));
        setSellerChats(formatted.filter(c => !c.otherParticipant?.store?.id));
      }
    } catch (error: any) {
      if (error.response?.status !== 401) console.error('Failed to load chats', error);
    }
  };

  useEffect(() => {
    let isMounted = true;

    const handleNewMessage = (data: any) => {
      const { message, conversationId } = data;
      const isMe = currentUserId && message.sender_id === currentUserId;

      const updateList = (prev: Conversation[]) => {
        if (!prev.some(c => c.id === conversationId)) {
          fetchChats();
          return prev;
        }

        const isViewing =
          pathnameRef.current === '/chat/conversation' &&
          conversationIdRef.current === conversationId;

        return prev
          .map(c =>
            c.id === conversationId
              ? {
                  ...c,
                  lastMessage: message.content,
                  time: new Date(message.created_at).toLocaleTimeString([], {
                    hour: '2-digit',
                    minute: '2-digit'
                  }),
                  unread: isMe || isViewing ? c.unread : c.unread + 1
                }
              : c
          )
          .sort((a, b) => (a.id === conversationId ? -1 : b.id === conversationId ? 1 : 0));
      };

      setBuyerChats(updateList);
      setSellerChats(updateList);
    };

    const handleIncomingCall = async (data: any) => {
      if (!isMounted) return;
      setCallData({ conversationId: data.conversationId, name: data.callerName, avatar: data.callerAvatar });
      setCallStatus('incoming');
      await playCallRingtone();
    };

    const handleAcceptedCall = async (data: any) => {
      if (!isMounted) return;
      await stopRingtone();
      setCallStatus('connected');
      const pc = await setupPeerConnection(data.conversationId);
      if (pc) {
        const offer = await pc.createOffer();
        await pc.setLocalDescription(offer);
        socketService.sendOffer(data.conversationId, offer);
      }
    };

    const handleRejectedCall = async () => {
      if (!isMounted) return;
      await stopRingtone();
      setCallStatus('ended');
      setTimeout(() => setCallStatus('idle'), 2000);
    };

    const handleEndedCall = async () => {
      if (!isMounted) return;
      await stopRingtone();
      setCallStatus('ended');
      setTimeout(() => setCallStatus('idle'), 2000);
    };

    const initSocket = async () => {
      try {
        const token =
          (await secureStorage.getItem('userToken')) ||
          (await secureStorage.getItem('businessToken'));
        if (!token) return;

        await socketService.connect();
        await socketService.onNewMessage(handleNewMessage);
        await socketService.onCallEvent('call:incoming', handleIncomingCall);
        await socketService.onCallEvent('call:accepted', handleAcceptedCall);
        await socketService.onCallEvent('call:rejected', handleRejectedCall);
        await socketService.onCallEvent('call:ended', handleEndedCall);
      } catch (err) {}
    };

    initSocket();

    return () => {
      isMounted = false;
      socketService.offNewMessage(handleNewMessage);
      socketService.offCallEvent('call:incoming', handleIncomingCall);
      socketService.offCallEvent('call:accepted', handleAcceptedCall);
      socketService.offCallEvent('call:rejected', handleRejectedCall);
      socketService.offCallEvent('call:ended', handleEndedCall);
    };
  }, [currentUserId, playCallRingtone]);

  const setupPeerConnection = async (conversationId: string) => {
    if (isExpoGo) { CustomInAppToast.show({ type: 'info', title: 'Not Supported', message: 'Calls require standalone app.' }); return; }
    const { RTCPeerConnection, mediaDevices } = await import('react-native-webrtc');
    const pc: any = new RTCPeerConnection({ iceServers: [{ urls: 'stun:stun.l.google.com:19302' }] });
    pc.onicecandidate = (e: any) => e.candidate && socketService.sendIceCandidate(conversationId, e.candidate);
    pc.ontrack = (e: any) => e.streams?.[0] && setRemoteStream(e.streams[0]);
    try {
      const { status } = await Audio.requestPermissionsAsync();
      if (status !== 'granted') return;
      await Audio.setAudioModeAsync({ allowsRecordingIOS: true, playsInSilentModeIOS: true, staysActiveInBackground: true, shouldDuckAndroid: true, playThroughEarpieceAndroid: false });
      const stream = await mediaDevices.getUserMedia({ audio: true, video: false });
      setLocalStream(stream);
      stream.getTracks().forEach((track: any) => pc.addTrack(track, stream));
    } catch {}
    peerConnection.current = pc;
    return pc;
  };

  useEffect(() => { fetchChats(); }, []);

  const cleanupCall = () => {
    if (localStream) { localStream.getTracks().forEach((t: any) => t.stop()); setLocalStream(null); }
    if (peerConnection.current) { peerConnection.current.close(); peerConnection.current = null; }
    setRemoteStream(null); setCallData(null); setIsMuted(false); setIsSpeakerOn(false);
  };

  const toggleMute = () => { if (localStream) { localStream.getAudioTracks().forEach((t: any) => t.enabled = !t.enabled); setIsMuted(!isMuted); } };
  const toggleSpeaker = async () => { const next = !isSpeakerOn; try { await Audio.setAudioModeAsync({ allowsRecordingIOS: true, playsInSilentModeIOS: true, staysActiveInBackground: true, shouldDuckAndroid: true, playThroughEarpieceAndroid: !next }); setIsSpeakerOn(next); } catch {} };

  const startCall = async (id: string, name: string, avatar: string) => { setCallData({ conversationId: id, name, avatar }); setCallStatus('outgoing'); await playCallRingtone(); await socketService.initiateCall(id, name, avatar); };
  const acceptCall = async () => { await stopRingtone(); if (callData) { setCallStatus('connected'); await setupPeerConnection(callData.conversationId); await socketService.acceptCall(callData.conversationId); } };
  const rejectCall = async () => { await stopRingtone(); if (callData) { setCallStatus('idle'); await socketService.rejectCall(callData.conversationId); cleanupCall(); } };
  const endCall = async () => { await stopRingtone(); if (callData) { setCallStatus('ended'); await socketService.endCall(callData.conversationId); cleanupCall(); setTimeout(() => setCallStatus('idle'), 2000); } };

  const sendMessage = async (id: string, text: string, type: 'buyer' | 'seller') => { if (socketService.isConnected()) await socketService.sendMessage(id, text); else await apiSendMessage(id, text); fetchChats(); };
  const markAsRead = async (id: string) => { try { await socketService.markConversationRead(id); } catch {} fetchChats(); };
  const deleteConversation = async (id: string) => { try { await apiDeleteConversation(id); return true; } catch { return false; } finally { fetchChats(); } };

  return (
    <ChatContext.Provider value={{ buyerConversations, sellerConversations, sendMessage, markAsRead, deleteConversation, refresh: fetchChats, currentUserId, callState, callData, startCall, acceptCall, rejectCall, endCall, isMuted, isSpeakerOn, toggleMute, toggleSpeaker }}>
      {children}
      <CallOverlay isVisible={callState !== 'idle'} status={callState === 'outgoing' ? 'outgoing' : callState === 'incoming' ? 'incoming' : callState === 'connected' ? 'connected' : 'ended'} name={callData?.name || 'Unknown'} avatar={callData?.avatar || ''} onAccept={acceptCall} onReject={rejectCall} onEnd={endCall} isMuted={isMuted} isSpeakerOn={isSpeakerOn} onToggleMute={toggleMute} onToggleSpeaker={toggleSpeaker} />
    </ChatContext.Provider>
  );
};

export const useChat = () => { const c = useContext(ChatContext); if (!c) throw new Error('useChat must be used within a ChatProvider'); return c; };

import { useEffect } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { queryKeys } from '@/lib/query/keys';
import * as ApiService from '@/services/api';
import { socketService } from '@/services/socket';
import { useRouter, usePathname } from 'expo-router';
import { Audio } from 'expo-av';
import * as Haptics from 'expo-haptics';
import { CustomInAppToast } from '@/components/InAppToastHost';

export const useNotifications = () => {
  const queryClient = useQueryClient();
  const router = useRouter();
  const pathname = usePathname();

  // Listen for real-time notification events via socket
  useEffect(() => {
    let mounted = true;

    const handleNewNotification = (data: any) => {
      if (!mounted) return;
      // Invalidate both notifications list and unread count so they refetch
      queryClient.invalidateQueries({ queryKey: queryKeys.notifications.list() });
      queryClient.invalidateQueries({ queryKey: queryKeys.notifications.unreadCount() });
    };

    // Connect socket and listen for notification:new events
    socketService.connect()
      .then((socket) => {
        socket.on('notification:new', handleNewNotification);
      })
      .catch((err) => {
        console.warn('Failed to connect socket for notifications:', err.message);
      });

    return () => {
      mounted = false;
      const socket = socketService.getSocket();
      if (socket) {
        socket.off('notification:new', handleNewNotification);
      }
    };
  }, [queryClient]);

  return useQuery({
    queryKey: queryKeys.notifications.list(),
    queryFn: async () => {
      const token = await ApiService.secureStorage.getItem('userToken') || 
                   await ApiService.secureStorage.getItem('businessToken');
      if (!token) return { notifications: [], unreadCount: 0 };
      
      const response = await ApiService.getNotifications();
      return response;
    },
    staleTime: 2 * 60 * 1000, // 2 minutes - notifications should be relatively fresh
    gcTime: 10 * 60 * 1000,
  });
};

export const useUnreadNotificationCount = (enableRealtime: boolean = true) => {
  const queryClient = useQueryClient();
  const router = useRouter();
  const pathname = usePathname();

  // Listen for real-time notification events via socket
  useEffect(() => {
    if (!enableRealtime) {
      return;
    }

    let mounted = true;

    const handleNewNotification = (data: any) => {
      if (!mounted) return;
      queryClient.invalidateQueries({ queryKey: queryKeys.notifications.unreadCount() });

      if (pathname !== '/notification' && data?.title && data?.message) {
        // Play haptic feedback and notification sound
        Haptics.notificationAsync(Haptics.NotificationFeedbackType.Success).catch(() => {});
        Audio.Sound.createAsync(
          require('@/assets/sounds/notification.wav'),
          { shouldPlay: true, volume: 0.25 } // soft chime, not full-blast
        )
          .then(({ sound }) => {
            sound.setOnPlaybackStatusUpdate((status) => {
              if (status.isLoaded && status.didJustFinish) {
                sound.unloadAsync(); // clean up memory
              }
            });
          })
          .catch((err) => console.warn('Failed to play notification sound:', err));

        CustomInAppToast.show({
          title: data.title,
          message: data.message,
          data: data,
        });
      }
    };

    socketService.connect()
      .then((socket) => {
        socket.on('notification:new', handleNewNotification);
      })
      .catch((err) => {
        console.warn('Failed to connect socket for unread count:', err.message);
      });

    return () => {
      mounted = false;
      const socket = socketService.getSocket();
      if (socket) {
        socket.off('notification:new', handleNewNotification);
      }
    };
  }, [enableRealtime, pathname, queryClient]);

  return useQuery({
    queryKey: queryKeys.notifications.unreadCount(),
    queryFn: async () => {
      const token = await ApiService.secureStorage.getItem('userToken') ||
                   await ApiService.secureStorage.getItem('businessToken');
      if (!token) return { unreadCount: 0 };

      const response = await ApiService.getUnreadNotificationCount();
      return response;
    },
    // This endpoint is lightweight; always refresh when a screen using it mounts.
    refetchOnMount: 'always',
    staleTime: 1 * 60 * 1000, // 1 minute
    gcTime: 5 * 60 * 1000,
  });
};

export const useMarkNotificationRead = () => {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async (notificationId: string) => {
      return await ApiService.markNotificationRead(notificationId);
    },
    onSuccess: (_data, notificationId) => {
      // Optimistically update cached list item read state
      queryClient.setQueryData(queryKeys.notifications.list(), (prev: any) => {
        if (!prev?.notifications) return prev;
        return {
          ...prev,
          notifications: prev.notifications.map((n: any) =>
            n.id === notificationId ? { ...n, is_read: true } : n
          )
        };
      });

      // Optimistically decrement unread badge count
      queryClient.setQueryData(queryKeys.notifications.unreadCount(), (prev: any) => {
        const current = Number(prev?.unreadCount || 0);
        return {
          ...(prev || {}),
          unreadCount: Math.max(0, current - 1)
        };
      });

      // Keep server state authoritative
      queryClient.invalidateQueries({ queryKey: queryKeys.notifications.list() });
      queryClient.invalidateQueries({ queryKey: queryKeys.notifications.unreadCount() });
    },
  });
};

export const useMarkAllNotificationsRead = () => {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async () => {
      return await ApiService.markAllNotificationsRead();
    },
    onSuccess: () => {
      // Optimistically clear unread state across the app
      queryClient.setQueryData(queryKeys.notifications.unreadCount(), (prev: any) => ({
        ...(prev || {}),
        unreadCount: 0
      }));

      queryClient.setQueryData(queryKeys.notifications.list(), (prev: any) => {
        if (!prev?.notifications) return prev;
        return {
          ...prev,
          notifications: prev.notifications.map((n: any) => ({ ...n, is_read: true }))
        };
      });

      // Invalidate notifications list to refetch
      queryClient.invalidateQueries({ queryKey: queryKeys.notifications.list() });
      queryClient.invalidateQueries({ queryKey: queryKeys.notifications.unreadCount() });
    },
  });
};

import axios from 'axios';

import AsyncStorage from '@react-native-async-storage/async-storage';
import * as SecureStore from 'expo-secure-store';
import { Platform } from 'react-native';
import { router } from 'expo-router';
import { queryClient } from '@/lib/query/client';
import { socketService } from './socket';
import { CustomInAppToast } from "@/components/InAppToastHost";
export { CustomInAppToast };

// API base URL sourced from Expo public environment.
const getBaseURL = () => {
  const apiUrl = process.env.EXPO_PUBLIC_API_URL?.trim();
  if (!apiUrl) {
    throw new Error('EXPO_PUBLIC_API_URL is not set');
  }
  return apiUrl.replace(/\/$/, '');
};

export const baseURL = getBaseURL();
export const API_URL = `${baseURL}/api/v1/`;

export const storage = {
  async getItem(key: string): Promise<string | null> {
    if (Platform.OS === 'web') return localStorage.getItem(key);
    return await AsyncStorage.getItem(key);
  },
  async setItem(key: string, value: string): Promise<void> {
    if (Platform.OS === 'web') localStorage.setItem(key, value);
    else await AsyncStorage.setItem(key, value);
  },
  async removeItem(key: string): Promise<void> {
    if (Platform.OS === 'web') localStorage.removeItem(key);
    else await AsyncStorage.removeItem(key);
  },
};

export const secureStorage = {
  async getItem(key: string): Promise<string | null> {
    if (Platform.OS === 'web') return localStorage.getItem(key);
    return await SecureStore.getItemAsync(key);
  },
  async setItem(key: string, value: string): Promise<void> {
    if (Platform.OS === 'web') localStorage.setItem(key, value);
    else await SecureStore.setItemAsync(key, value);
  },
  async removeItem(key: string): Promise<void> {
    if (Platform.OS === 'web') localStorage.removeItem(key);
    else await SecureStore.deleteItemAsync(key);
  },
};
 
// ─── Error message extractor ──────────────────────────────────────────────────
export const extractErrorMessage = (error: any): string => {
  if (error?.response) {
    const { status, data } = error.response;
    const serverMsg = data?.error || data?.message;
    if (serverMsg && typeof serverMsg === 'string' && serverMsg !== 'Internal Server Error') {
      return serverMsg;
    }
    switch (status) {
      case 400: return serverMsg || 'Invalid request. Please check your input and try again.';
      case 401: return 'Your session has expired. Please log in again.';
      case 403: return serverMsg || "You don't have permission to perform this action.";
      case 404: return serverMsg || 'The requested resource was not found.';
      case 408: return 'Request timed out. Please check your connection and try again.';
      case 409: return serverMsg || 'This action conflicts with existing data.';
      case 413: return 'The file you uploaded is too large. Please try a smaller file.';
      case 422: return serverMsg || 'Please check your input — some fields are invalid.';
      case 429: return 'Too many requests. Please wait a moment and try again.';
      case 500: return 'Server error. Please try again later.';
      case 502: return 'Server is temporarily unreachable. Please try again in a moment.';
      case 503: return 'Service is temporarily unavailable. Please try again later.';
      default: return serverMsg || `Something went wrong (error ${status}). Please try again.`;
    }
  }
  if (error?.request) {
    if (error.code === 'ECONNABORTED') return 'Request timed out. Please check your internet connection.';
    return 'No internet connection. Please check your network and try again.';
  }
  if (error?.message) {
    if (error.message.includes('Network Error')) return 'No internet connection. Please check your network and try again.';
    return error.message;
  }
  return 'An unexpected error occurred. Please try again.';
};
 
// ─── FIX 2: 429 exponential backoff helper ────────────────────────────────────
// Waits for the delay indicated by Retry-After header (seconds) if present,
// otherwise uses exponential backoff: attempt 0→1s, 1→2s, 2→4s.
const wait = (ms: number) => new Promise((resolve) => setTimeout(resolve, ms));
 
const get429DelayMs = (error: any, attempt: number): number => {
  const retryAfter = error?.response?.headers?.['retry-after'];
  if (retryAfter) {
    const seconds = parseInt(retryAfter, 10);
    if (!isNaN(seconds)) return seconds * 1000;
  }
  // Exponential backoff: 1s, 2s, 4s
  return Math.pow(2, attempt) * 1000;
};
 
// ─── Axios instance ───────────────────────────────────────────────────────────
export const api = axios.create({
  baseURL: API_URL,
  headers: { 'Content-Type': 'application/json' },
});

api.interceptors.request.use(
  async (config) => {
    try {
      const token = await secureStorage.getItem('userToken') || await secureStorage.getItem('businessToken');
      if (token) config.headers.Authorization = `Bearer ${token}`;
    } catch (error) {
      console.error('Error getting token from storage:', error);
    }
    return config;
  },
  (error) => Promise.reject(error)
);
 
// ─── Token refresh queue ──────────────────────────────────────────────────────
let isRefreshing = false;
let failedQueue: { resolve: (value: any) => void; reject: (reason?: any) => void }[] = [];
 
const processQueue = (error: any, token: string | null = null) => {
  failedQueue.forEach((prom) => {
    if (error) prom.reject(error);
    else prom.resolve(token);
  });
  failedQueue = [];
};
 
// ─── Response interceptor ─────────────────────────────────────────────────────
api.interceptors.response.use(
  (response) => response,
  async (error) => {
    error.userMessage = extractErrorMessage(error);
 
    const originalRequest = error.config;
 
    // ── FIX 2: Handle 429 rate limiting with exponential backoff ──────────────
    if (error.response?.status === 429) {
      // Track retry count on the request config object
      originalRequest._429RetryCount = (originalRequest._429RetryCount ?? 0);
 
      const MAX_429_RETRIES = 3;
 
      if (originalRequest._429RetryCount < MAX_429_RETRIES) {
        const attempt = originalRequest._429RetryCount;
        originalRequest._429RetryCount += 1;
 
        const delayMs = get429DelayMs(error, attempt);
        console.warn(`[429] Rate limited. Retrying in ${delayMs}ms (attempt ${attempt + 1}/${MAX_429_RETRIES})`);
 
        await wait(delayMs);
        return api(originalRequest);
      }
 
      // Exhausted retries — show Toast and reject
      CustomInAppToast.show({
        type: 'error',
        title: 'Too many requests',
        message: 'Please slow down and try again in a moment.',
      });
 
      return Promise.reject(error);
    }
 
    // ── Handle 401 token expiry with silent refresh ───────────────────────────
    const isTokenExpired =
      error.response?.status === 401 &&
      (error.response?.data?.code === 'TOKEN_EXPIRED' ||
        error.response?.data?.error === 'Access token expired');
 
    if (isTokenExpired && !originalRequest._retry) {
      if (isRefreshing) {
        return new Promise((resolve, reject) => {
          failedQueue.push({ resolve, reject });
        })
          .then((token) => {
            originalRequest.headers.Authorization = `Bearer ${token}`;
            return api(originalRequest);
          })
          .catch((err) => Promise.reject(err));
      }
 
      originalRequest._retry = true;
      isRefreshing = true;
 
      try {
        const storedRefreshToken = await secureStorage.getItem('refreshToken');
        if (!storedRefreshToken) throw new Error('No refresh token stored');
 
        const refreshRes = await api.post('/auth/refresh', {
          refreshToken: storedRefreshToken,
        });
        const { token: newAccessToken, refreshToken: newRefreshToken } = refreshRes.data;
 
        await secureStorage.setItem('userToken', newAccessToken);
        if (newRefreshToken) await secureStorage.setItem('refreshToken', newRefreshToken);
 
        api.defaults.headers.common['Authorization'] = `Bearer ${newAccessToken}`;
 
        // FIX 4: Also update the socket auth token so it doesn't stay stale
        // after a silent refresh. Socket will re-authenticate on next emit.
        try {
          const sock = socketService.getSocket();
          if (sock) {
            sock.auth = { token: newAccessToken };
          }
        } catch (_) {}
 
        processQueue(null, newAccessToken);
        originalRequest.headers.Authorization = `Bearer ${newAccessToken}`;
        return api(originalRequest);
      } catch (refreshError) {
        processQueue(refreshError, null);
        try {
          await secureStorage.removeItem('userToken');
          await secureStorage.removeItem('refreshToken');
          await storage.removeItem('userId');
        } catch (_) {}
        return Promise.reject(refreshError);
      } finally {
        isRefreshing = false;
      }
    }
    // ── Non-expiry 401: clear storage ─────────────────────────────────────────
    if (error.response?.status === 401 && !originalRequest._retry) {
      try {
        // Check if token existed before clearing — helps prevent double redirects during manual logout
        const existingToken = await secureStorage.getItem('userToken');
        
        await secureStorage.removeItem('userToken');
        await secureStorage.removeItem('refreshToken');
        await storage.removeItem('userId');

        // Only force redirect if we haven't already cleared the session manually
        if (existingToken) {
          router.replace('/login');
        }
      } catch (storageError) {
        console.error('Error clearing tokens:', storageError);
      }
    }
 
    return Promise.reject(error);
  }
